import { Column } from 'typeorm';
import { UuidTransformer } from '../transformer/uuid-transformer.js';

/**
 * Autogenerated uuid7 column
 *
 * @returns
 */
export function UuidColumn(): PropertyDecorator {
    return (...args) => {
        Column({
            type: 'uuid',
            unique: true,
            transformer: new UuidTransformer(),
        })(...args);
    };
}
